 运动员最佳匹配问题 问题前面就不多说，简单模拟得到矩阵。
然后对矩阵用匈牙利得到最小匹配。
我累了，看代码吧
#include &lt;bits/stdc++.h&gt; using namespace std; const int MAXN = 25; int n; int P[MAXN][MAXN], Q[MAXN][MAXN]; int cost[MAXN][MAXN]; int u[MAXN], v[MAXN], p[MAXN], way[MAXN]; int hungarian() { for (int i = 1; i &lt;= n; i++) { p[0] = i; int j0 = 0; vector&lt;int&gt; minv(n+1, INT_MAX); vector&lt;bool&gt; used(n+1, false); do { used[j0] = true; int i0 = p[j0], delta = INT_MAX, j1 = 0; for (int j = 1; j &lt;= n; j++) { if (!used[j]) { int cur = -cost[i0][j] - u[i0] - v[j]; // 取负数求最大匹配 if (cur &lt; minv[j]) { minv[j] = cur; way[j] = j0; } if (minv[j] &lt; delta) { delta = minv[j]; j1 = j; } } } for (int j = 0; j &lt;= n; j++) { if (used[j]) { u[p[j]] += delta; v[j] -= delta; } else { minv[j] -= delta; } } j0 = j1; } while (p[j0] != 0); do { int j1 = way[j0]; p[j0] = p[j1]; j0 = j1; } while (j0); } int result = 0; for (int j = 1; j &lt;= n; j++) result += cost[p[j]][j]; return result; } int main() { cin &gt;&gt; n; for (int i = 0; i &lt; n; i++) for (int j = 0; j &lt; n; j++) cin &gt;&gt; P[i][j]; for (int i = 0; i &lt; n; i++) for (int j = 0; j &lt; n; j++) cin &gt;&gt; Q[i][j]; // 构造竞赛优势矩阵 for (int i = 0; i &lt; n; i++) for (int j = 0; j &lt; n; j++) cost[i+1][j+1] = P[i][j] * Q[j][i]; cout &lt;&lt; hungarian() &lt;&lt; endl; return 0; }

失踪的7 直接找pascal的n以内的最大值
由于需要删除7（单位大于7就减，小于7直接用）,所以可以把十进制转换为去除7的模拟九进制。
#include &lt;bits/stdc++.h&gt; using namespace std; #define ll long long int main() { int t; cin &gt;&gt; t; while(t--) { string s; cin &gt;&gt; s; ll result = 0; for(char c : s) { int dig = c-&#39;0&#39;; if(dig &gt; 7) dig--; result = result*9 + dig; } cout &lt;&lt; result &lt;&lt; &#34;\n&#34;; } return 0; }

感觉KMP很简单就没练过，用的时候太不熟练，写个博客熟悉熟悉。
其实主要就是两部分，一个是确定next数组，一个是利用next找子串，这两部分大致思路很简单，有点异曲同工。
具体细节代码中注释已经说的很清楚了，不再赘述。
#include&lt;bits/stdc++.h&gt; using namespace std; vector&lt;int&gt; getNext(const string &amp;pattern) { int m = pattern.size(); // 既可以用来初始化也可以作为循环出口 vector&lt;int&gt; next(m); next.push_back(0); // 一个字符无法匹配默认为0 int i=1; // 后缀匹配到的字符位置（只增不减） int p=0; // 记录当前最大前缀(末)位置(其实也就是p=next[0]) while(i&lt;m) { if(next[p] == next[i]) { p++; // 缀数增加，要推进主串，同时构建next next.push_back(p); i++; // 向后推进 } else // 后缀断连 { if(p == 0) // 没有回退空间（找不到更小前后缀）,保持缀数不变,继续推进 { i++; } else { p = next[p-1]; // 前后缀长度回退，循环继续 } } } return next; } int main() { string text;// 原串 string pattern;// 要找的目标字符串 cin &gt;&gt; text; cin &gt;&gt; pattern; int n=text.size(); int m=pattern.size(); if(n &lt; m) return 0; //长度不符合标准 vector&lt;int&gt; next = getNext(text); // 这里只处理查找到第一个匹配串的位置，如果多个匹配点,重置变量(p),继续匹配不间断输出就行 int j=0; // pattern(副)串匹配到的位置 int i=0; // text(主)串匹配到的位置 while(j&lt;m) { if(pattern[j] == text[i]) { j++; i++; } else { if(j==0) // 无法回退 { i++; // 向前推进 } else { j = next[j-1]; } } } // 这时i位于找到的子串所在位置后面一个 printf(&#34;第一个匹配的子串位置是[%d,%d]\n&#34;,i-m,i-1); // 输出所在区间 return 0; }
